func (c *current) onSelectOrCall1(left, selection any) (any, error) {
	switch sel := selection.(type) {
	case *ObjectSelection:
		// Object selection: obj.{field1, field2}
		sel.Receiver = left.(Node)
		return sel, nil
	case []interface{}:
		// Regular field access with optional args
		name := sel[0].(*Symbol)
		args := sel[1]
		blockArg := sel[2]
		if args != nil || blockArg != nil {
			// Select followed by () and/or block - create FunCall
			var argRecord Record
			if args != nil {
				argRecord = Record(args.([]Keyed[Node]))
			}

			var block *BlockArg
			if blockArg != nil {
				block = blockArg.(*BlockArg)
			}

			return &FunCall{
				Fun: &Select{
					Receiver: left.(Node),
					Field:    name,
					Loc:      c.Loc(),
				},
				Args:     argRecord,
				BlockArg: block,
				Loc:      c.Loc(),
			}, nil
		} else {
			// Just a Select
			return &Select{
				Receiver: left.(Node),
				Field:    name,
				AutoCall: true,
				Loc:      c.Loc(),
			}, nil
		}
	default:
		return nil, fmt.Errorf("unexpected selection type")
	}
}

func (p *parser) callonSelectOrCall1() (any, error) {
	stack := p.vstack[len(p.vstack)-1]
	_ = stack
	return p.cur.onSelectOrCall1(stack["left"], stack["selection"])
}

func (c *current) onIndexOrCall1(left, index, args any) (any, error) {
	if args != nil {
		// Index followed by () - create FunCall
		argRecord := Record(args.([]Keyed[Node]))
		return &FunCall{
			Fun: &Index{
				Receiver: left.(Node),
				Index:    index.(Node),
				Loc:      c.Loc(),
			},
			Args: argRecord,
			Loc:  c.Loc(),
		}, nil
	} else {
		// Just an Index
		return &Index{
			Receiver: left.(Node),
			Index:    index.(Node),
			AutoCall: true,
			Loc:      c.Loc(),
		}, nil
	}
}

